import { z } from 'zod';
import {
  PluginError,
  makeAgentContext,
  type AgentContext,
  type Plugin,
  type ToolDescriptor,
} from '@ax/core';

const PLUGIN_NAME = '@ax/test-harness/test-host-echo';
const TOOL_NAME = 'test-host-echo';
const EXECUTE_HOOK = `tool:execute:${TOOL_NAME}` as const;

