22	  description?: string;
23	  // JSON Schema for the tool's input. Required so LLM providers can forward
24	  // the shape to the model. Kept as an opaque object so plugins can emit any
25	  // valid JSON Schema draft without coupling to a specific zod version.
26	  inputSchema: Record<string, unknown>;
27	  /**
28	   * Where the tool physically runs:
29	   * - `'sandbox'`: the agent runtime dispatches locally, never hits the host.
30	   * - `'host'`: the agent sends `tool.execute-host` and waits for the host.
31	   *
32	   * Must match the corresponding field on `@ax/ipc-protocol`'s
33	   * `ToolDescriptorSchema` — see that file for the cross-boundary shape.
34	   */
35	  executesIn: 'sandbox' | 'host';
36	}
37	
38	export type AgentOutcome =
39	  | { kind: 'complete'; messages: AgentMessage[] }
40	  | { kind: 'terminated'; reason: string; error?: unknown };
41	
42	export type FireResult<P> =
43	  | { rejected: false; payload: P }
44	  | Rejection;
45	
46	/**
47	 * Canonical input to the `llm:call` service hook.
48	 *
49	 * Provider-agnostic. The registrar plugin (e.g. `@ax/llm-anthropic`) is
50	 * responsible for translating to its SDK's request shape. Optional fields
51	 * fall back to plugin-level defaults — callers that don't care about model
52	 * selection or output cap can pass just `messages`.
53	 *
