import {
  makeAgentContext,
  type AgentContext,
  type Plugin,
  type ToolDescriptor,
} from '@ax/core';
import { ARTIFACT_PUBLISH_DESCRIPTOR } from './descriptor.js';

const PLUGIN_NAME = '@ax/tool-artifact-publish';

